query:
query GetEvents(
  $code:      String!
  $fightIDs:  [Int]!
  $startTime: Float!
  $endTime:   Float!
  $type:      EventDataType!
) {
  reportData {
    report(code: $code) {
      events(
        fightIDs:        $fightIDs
        startTime:       $startTime
        endTime:         $endTime
        dataType:        $type
        includeResources: true
      ) {
        data
        nextPageTimestamp
      }
    }
  }
}
